{"code": "import json

# Get review data from previous query
review_data = locals()['var_functions.query_db:12']

# Group reviews by gmap_id and calculate average ratings
from collections import defaultdict

ratings_by_business = defaultdict(list)
for review in review_data:
    gmap_id = review['gmap_id']
    rating = int(review['rating'])
    ratings_by_business[gmap_id].append(rating)

# Calculate average ratings
average_ratings = {}
for gmap_id, ratings in ratings_by_business.items():
    average_ratings[gmap_id] = sum(ratings) / len(ratings)

print('__RESULT__:')
print(json.dumps({
    "average_ratings": average_ratings,
    "business_counts": {gmap_id: len(ratings) for gmap_id, ratings in ratings_by_business.items()}
}))"}

